<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Expense Tracker</title>
<style>
  body { font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif; max-width: 600px; margin: 2rem auto; padding: 0 1rem; line-height: 1.5; }
  h1 { margin-top: 0; font-size: 1.5rem; }

  /* Form Styles */
  .form-group { display: flex; gap: 0.5rem; align-items: center; flex-wrap: wrap; margin-bottom: 1rem; }
  input, select, button { padding: 0.5rem; font-size: 1rem; border: 1px solid #ccc; border-radius: 4px; }
  label { white-space: nowrap; }

  /* Error Message */
  #form-error { color: #d32f2f; min-height: 1.5em; margin-bottom: 1rem; font-weight: bold; }

  /* Filters Section */
  .filters { background: #f4f6f8; padding: 1rem; border-radius: 6px; margin-bottom: 1rem; display: flex; gap: 0.5rem; align-items: center; flex-wrap: wrap; }

  /* Summary Section */
  #total { font-size: 1.25rem; font-weight: bold; margin-bottom: 1rem; padding: 0.5rem; background: #e8f5e9; border-radius: 4px; display: inline-block; }

  .category-summaries { display: flex; gap: 1rem; margin-bottom: 1rem; flex-wrap: wrap; }
  .cat-total { background: #fff; border: 1px solid #ddd; padding: 0.25rem 0.5rem; border-radius: 4px; font-size: 0.9rem; min-width: 80px; text-align: center; }

  /* List Styles */
  ul { list-style: none; padding: 0; margin: 0; }
  li.expense { display: flex; justify-content: space-between; align-items: flex-start; padding: 0.75rem; border-bottom: 1px solid #eee; background: #fff; transition: background 0.2s; }
  li.expense:hover { background: #fafafa; }
  li.expense:last-child { border-bottom: none; }

  .expense-info { display: flex; flex-direction: column; gap: 0.25rem; }
  .expense-amount { font-weight: bold; color: #333; }
  .expense-meta { font-size: 0.85rem; color: #666; }

  button.exp-del { background: #dc3545; color: white; border: none; padding: 0.25rem 0.75rem; cursor: pointer; border-radius: 4px; font-size: 0.85rem; margin-left: 1rem; }
  button.exp-del:hover { background: #c82333; }

</style>
</head>
<body>

<h1>Personal Expense Tracker</h1>

<form id="expense-form">
  <div class="form-group">
    <label for="amount">Amount:</label>
    <input type="number" id="amount" step="0.01" placeholder="0.00">

    <label for="category">Category:</label>
    <select id="category">
      <option value="groceries">Groceries</option>
      <option value="transport">Transport</option>
      <option value="bills">Bills</option>
      <option value="fun">Fun</option>
    </select>

    <label for="date">Date:</label>
    <input type="date" id="date">

    <label for="note">Note:</label>
    <input type="text" id="note" placeholder="Optional">
  </div>
  <button type="submit" id="add-expense">Add Expense</button>
</form>

<div id="form-error"></div>

<div class="filters">
  <label for="filter-category">Category:</label>
  <select id="filter-category">
    <option value="all">All Categories</option>
    <option value="groceries">Groceries</option>
    <option value="transport">Transport</option>
    <option value="bills">Bills</option>
    <option value="fun">Fun</option>
  </select>

  <label for="filter-from">From:</label>
  <input type="date" id="filter-from">

  <label for="filter-to">To:</label>
  <input type="date" id="filter-to">
</div>

<div id="total">Total: 0.00</div>

<div class="category-summaries">
  <span class="cat-total" data-cat="groceries">Groceries: 0.00</span>
  <span class="cat-total" data-cat="transport">Transport: 0.00</span>
  <span class="cat-total" data-cat="bills">Bills: 0.00</span>
  <span class="cat-total" data-cat="fun">Fun: 0.00</span>
</div>

<ul id="expense-list"></ul>

<script>
(function() {
    // State Management
    let expenses = [];

    // DOM Elements
    const form = document.getElementById('expense-form');
    const amountInput = document.getElementById('amount');
    const categoryInput = document.getElementById('category');
    const dateInput = document.getElementById('date');
    const noteInput = document.getElementById('note');
    const errorDiv = document.getElementById('form-error');
    const listEl = document.getElementById('expense-list');
    const totalEl = document.getElementById('total');
    const catTotals = document.querySelectorAll('.cat-total');

    // Filter Elements
    const filterCategory = document.getElementById('filter-category');
    const filterFrom = document.getElementById('filter-from');
    const filterTo = document.getElementById('filter-to');

    // Load from localStorage on startup
    function loadExpenses() {
        try {
            const stored = localStorage.getItem('expenses');
            if (stored) {
                expenses = JSON.parse(stored);
            }
        } catch (e) {
            console.error("Failed to parse expenses", e);
            expenses = [];
        }
    }

    // Save current state to localStorage
    function saveExpenses() {
        try {
            localStorage.setItem('expenses', JSON.stringify(expenses));
        } catch (e) {
            console.error("Failed to save expenses", e);
        }
    }

    // Validation Logic
    function validateForm() {
        const amountVal = parseFloat(amountInput.value);
        const dateVal = dateInput.value.trim();

        if (!amountInput.value || isNaN(amountVal) || amountVal <= 0) {
            return "Amount must be a positive number.";
        }
        if (!dateVal) {
            return "Date is required.";
        }
        return null; // Valid
    }

    // Render List & Summary based on current filters
    function render() {
        const catFilter = filterCategory.value;
        const fromFilter = filterFrom.value.trim();
        const toFilter = filterTo.value.trim();

        // Filter Logic
        let filteredExpenses = expenses.filter(exp => {
            // Category Filter
            if (catFilter !== 'all' && exp.category !== catFilter) return false;

            // Date Range Filters (ISO strings compare correctly lexicographically)
            if (fromFilter && exp.date < fromFilter) return false;
            if (toFilter && exp.date > toFilter) return false;

            return true;
        });

        // Sort: Newest first (Date desc). If dates equal, keep original order or sort by ID.
        filteredExpenses.sort((a, b) => {
            if (a.date === b.date) return 0; 
            return a.date < b.date ? 1 : -1;
        });

        // Calculate Totals for Visible Expenses
        let totalSum = 0;
        const catSums = { groceries: 0, transport: 0, bills: 0, fun: 0 };

        filteredExpenses.forEach(exp => {
            const amt = parseFloat(exp.amount);
            totalSum += amt;
            if (catSums.hasOwnProperty(exp.category)) {
                catSums[exp.category] += amt;
            }
        });

        // Update Total Display
        totalEl.textContent = `Total: ${totalSum.toFixed(2)}`;

        // Update Category Displays
        catTotals.forEach(el => {
            const cat = el.getAttribute('data-cat');
            const sum = catSums[cat] || 0;
            // Format text to contain the total (e.g., "Groceries: 10.50")
            el.textContent = `${el.getAttribute('data-cat').charAt(0).toUpperCase() + el.getAttribute('data-cat').slice(1)}: ${sum.toFixed(2)}`;
        });

        // Render List Items
        listEl.innerHTML = '';

        if (filteredExpenses.length === 0) {
            const li = document.createElement('li');
            li.textContent = 'No expenses found.';
            li.style.padding = '1rem';
            li.style.textAlign = 'center';
            li.style.color = '#666';
            listEl.appendChild(li);
        } else {
            filteredExpenses.forEach(exp => {
                const li = document.createElement('li');
                li.className = 'expense';

                li.innerHTML = `
                    <div class="expense-info">
                        <span class="expense-amount">$${parseFloat(exp.amount).toFixed(2)}</span>
                        <span class="expense-meta">${exp.category} • ${exp.date}</span>
                        ${exp.note ? `<small style="color:#555;">"${exp.note}"</small>` : ''}
                    </div>
                    <button type="button" class="exp-del" data-id="${exp.id}">Delete</button>
                `;

                listEl.appendChild(li);
            });
        }
    }

    // Add Expense Handler
    form.addEventListener('submit', (e) => {
        e.preventDefault();

        const error = validateForm();
        if (error) {
            errorDiv.textContent = error;
            return;
        }

        const newExpense = {
            id: Date.now().toString(), // Unique ID based on timestamp
            amount: parseFloat(amountInput.value),
            category: categoryInput.value,
            date: dateInput.value,
            note: noteInput.value || ''
        };

        expenses.push(newExpense);
        saveExpenses();

        // Reset Amount and Error as per contract
        amountInput.value = '';
        errorDiv.textContent = '';

        render();
    });

    // Delete Handler (Event Delegation)
    listEl.addEventListener('click', (e) => {
        if (e.target.classList.contains('exp-del')) {
            const idToDelete = e.target.getAttribute('data-id');
            expenses = expenses.filter(exp => exp.id !== idToDelete);
            saveExpenses();
            render();
        }
    });

    // Filter Change Handlers
    [filterCategory, filterFrom, filterTo].forEach(el => {
        el.addEventListener('input', render);
    });

    // Initialize App
    loadExpenses();
    render();

})();
</script>
</body>
</html>
